package fibonacci

// fibonacci returns the nth Fibonacci number using iterative approach.
// Time complexity: O(n), Space complexity: O(1)
func fibonacci(n int) int {
	if n <= 0 {
		return 0
	}
	if n == 1 {
		return 1
	}
	a, b := 0, 1
	for i := 2; i <= n; i++ {
		a, b = b, a+b
	}
	return b
}

// fibonacciRecursive returns the nth Fibonacci number using recursion.
// Time complexity: O(2^n), Space complexity: O(n) due to call stack.
// WARNING: Very slow for n > 40. Use fibonacci() for production code.
func fibonacciRecursive(n int) int {
	if n <= 0 {
		return 0
	}
	if n == 1 {
		return 1
	}
	return fibonacciRecursive(n-1) + fibonacciRecursive(n-2)
}

// fibonacciMemoized returns the nth Fibonacci number using memoization.
// Time complexity: O(n), Space complexity: O(n)
func fibonacciMemoized(n int) int {
	memo := make(map[int]int)
	return fibHelper(n, memo)
}

func fibHelper(n int, memo map[int]int) int {
	if n <= 0 {
		return 0
	}
	if n == 1 {
		return 1
	}
	if val, ok := memo[n]; ok {
		return val
	}
	result := fibHelper(n-1, memo) + fibHelper(n-2, memo)
	memo[n] = result
	return result
}

// fibonacciChan returns a channel that yields Fibonacci numbers.
// The channel is closed after yielding the first n numbers.
func fibonacciChan(n int) <-chan int {
	ch := make(chan int)
	go func() {
		defer close(ch)
		a, b := 0, 1
		for i := 0; i < n; i++ {
			ch <- a
			a, b = b, a+b
		}
	}()
	return ch
}

// fibonacciSlice returns a slice of the first n Fibonacci numbers.
func fibonacciSlice(n int) []int {
	if n <= 0 {
		return nil
	}
	result := make([]int, n)
	result[0] = 0
	if n > 1 {
		result[1] = 1
	}
	for i := 2; i < n; i++ {
		result[i] = result[i-1] + result[i-2]
	}
	return result
}

// fibonacciMatrix returns the nth Fibonacci number using matrix exponentiation.
// Time complexity: O(log n), Space complexity: O(1)
func fibonacciMatrix(n int) int {
	if n <= 0 {
		return 0
	}
	if n == 1 {
		return 1
	}

	result := [2][2]int{{1, 0}, {0, 1}}
	base := [2][2]int{{1, 1}, {1, 0}}

	n--
	for n > 0 {
		if n%2 == 1 {
			result = multiplyMatrices(result, base)
		}
		base = multiplyMatrices(base, base)
		n /= 2
	}
	return result[0][0]
}

func multiplyMatrices(a, b [2][2]int) [2][2]int {
	return [2][2]int{
		{a[0][0]*b[0][0] + a[0][1]*b[1][0], a[0][0]*b[0][1] + a[0][1]*b[1][1]},
		{a[1][0]*b[0][0] + a[1][1]*b[1][0], a[1][0]*b[0][1] + a[1][1]*b[1][1]},
	}
}
